#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <dirent.h>
#include <sys/stat.h>
#include <unistd.h>
#include <time.h>

#define MINIGIT_DIR ".minigit"
#define INDEX_FILE ".minigit/index"
#define COMMITS_DIR ".minigit/commits"
#define MAX_FILES 100
#define MAX_FILENAME 256
#define MAX_COMMITS 100
#define HASH_SIZE 40

typedef struct {
    char filename[MAX_FILENAME];
    char hash[HASH_SIZE];
} IndexEntry;

typedef struct {
    IndexEntry files[MAX_FILES];
    int count;
} Index;

typedef struct {
    char hash[HASH_SIZE];
    char message[1024];
    time_t timestamp;
    char parent[HASH_SIZE];
    Index snapshot;
} Commit;

int directory_exists(const char* path) {
    struct stat st;
    return stat(path, &st) == 0 && S_ISDIR(st.st_mode);
}

int file_exists(const char* path) {
    struct stat st;
    return stat(path, &st) == 0 && S_ISREG(st.st_mode);
}

void compute_hash(const char* content, size_t len, char* out) {
    snprintf(out, HASH_SIZE, "%zu", len);
}

void read_index(Index* idx) {
    idx->count = 0;
    FILE* f = fopen(INDEX_FILE, "r");
    if (!f) return;
    while (fscanf(f, "%s %s\n", idx->files[idx->count].filename, idx->files[idx->count].hash) == 2) {
        idx->count++;
    }
    fclose(f);
}

void write_index(const Index* idx) {
    FILE* f = fopen(INDEX_FILE, "w");
    for (int i = 0; i < idx->count; i++) {
        fprintf(f, "%s %s\n", idx->files[i].filename, idx->files[i].hash);
    }
    fclose(f);
}

void read_file_content(const char* filename, char** content, size_t* len) {
    FILE* f = fopen(filename, "rb");
    if (!f) { *content = NULL; *len = 0; return; }
    fseek(f, 0, SEEK_END);
    *len = ftell(f);
    fseek(f, 0, SEEK_SET);
    *content = malloc(*len + 1);
    fread(*content, 1, *len, f);
    (*content)[*len] = '\0';
    fclose(f);
}

void write_file_content(const char* filename, const char* content, size_t len) {
    FILE* f = fopen(filename, "wb");
    fwrite(content, 1, len, f);
    fclose(f);
}

void copy_file(const char* src, const char* dst) {
    char* content;
    size_t len;
    read_file_content(src, &content, &len);
    write_file_content(dst, content, len);
    free(content);
}

void cmd_init() {
    if (directory_exists(MINIGIT_DIR)) {
        printf("Repository already initialized\n");
        return;
    }
    mkdir(MINIGIT_DIR, 0755);
    mkdir(COMMITS_DIR, 0755);
    FILE* f = fopen(INDEX_FILE, "w");
    fclose(f);
    printf("Initialized empty minigit repository\n");
}

void cmd_add(const char* filename) {
    if (!file_exists(filename)) {
        printf("File %s does not exist\n", filename);
        return;
    }
    char* content;
    size_t len;
    read_file_content(filename, &content, &len);
    char hash[HASH_SIZE];
    compute_hash(content, len, hash);
    free(content);

    Index idx;
    read_index(&idx);

    int found = 0;
    for (int i = 0; i < idx.count; i++) {
        if (strcmp(idx.files[i].filename, filename) == 0) {
            strcpy(idx.files[i].hash, hash);
            found = 1;
            break;
        }
    }
    if (!found) {
        strcpy(idx.files[idx.count].filename, filename);
        strcpy(idx.files[idx.count].hash, hash);
        idx.count++;
    }
    write_index(&idx);
}

void save_commit(const Commit* commit) {
    char path[512];
    snprintf(path, sizeof(path), "%s/%s.commit", COMMITS_DIR, commit->hash);
    FILE* f = fopen(path, "wb");
    fwrite(commit, sizeof(Commit), 1, f);
    fclose(f);
}

int load_commit(const char* hash, Commit* commit) {
    char path[512];
    snprintf(path, sizeof(path), "%s/%s.commit", COMMITS_DIR, hash);
    FILE* f = fopen(path, "rb");
    if (!f) return 0;
    fread(commit, sizeof(Commit), 1, f);
    fclose(f);
    return 1;
}

void cmd_commit(const char* message) {
    Index idx;
    read_index(&idx);
    if (idx.count == 0) {
        printf("No changes to commit\n");
        return;
    }

    Commit commit;
    memset(&commit, 0, sizeof(commit));
    strcpy(commit.message, message);
    commit.timestamp = time(NULL);
    commit.snapshot = idx;

    Commit parent;
    int has_parent = 0;
    FILE* f = fopen(".minigit/HEAD", "r");
    if (f) {
        char head[HASH_SIZE];
        fscanf(f, "%s", head);
        fclose(f);
        if (load_commit(head, &parent)) {
            has_parent = 1;
            strcpy(commit.parent, parent.hash);
        }
    }

    char head[HASH_SIZE];
    compute_hash((char*)&commit, sizeof(commit), head);
    strcpy(commit.hash, head);

    for (int i = 0; i < idx.count; i++) {
        char dst[512];
        snprintf(dst, sizeof(dst), "%s/%s", COMMITS_DIR, idx.files[i].hash);
        if (!file_exists(dst)) {
            copy_file(idx.files[i].filename, dst);
        }
    }

    save_commit(&commit);

    f = fopen(".minigit/HEAD", "w");
    fprintf(f, "%s\n", head);
    fclose(f);

    printf("Committed with hash %s\n", head);
}

void cmd_checkout(const char* version_str) {
    int version = atoi(version_str);
    char head[HASH_SIZE];
    FILE* f = fopen(".minigit/HEAD", "r");
    if (!f) {
        printf("No commits found\n");
        return;
    }
    fscanf(f, "%s", head);
    fclose(f);

    Commit commit;
    if (!load_commit(head, &commit)) {
        printf("Failed to load commit\n");
        return;
    }

    for (int i = 0; i < version; i++) {
        if (strlen(commit.parent) == 0) {
            printf("Invalid version\n");
            return;
        }
        load_commit(commit.parent, &commit);
    }

    for (int i = 0; i < commit.snapshot.count; i++) {
        char src[512];
        snprintf(src, sizeof(src), "%s/%s", COMMITS_DIR, commit.snapshot.files[i].hash);
        copy_file(src, commit.snapshot.files[i].filename);
    }

    Index idx = commit.snapshot;
    write_index(&idx);
}

void cmd_reset(const char* version_str) {
    int version = atoi(version_str);
    char head[HASH_SIZE];
    FILE* f = fopen(".minigit/HEAD", "r");
    if (!f) {
        printf("No commits found\n");
        return;
    }
    fscanf(f, "%s", head);
    fclose(f);

    Commit commit;
    if (!load_commit(head, &commit)) {
        printf("Failed to load commit\n");
        return;
    }

    for (int i = 0; i < version; i++) {
        if (strlen(commit.parent) == 0) {
            printf("Invalid version\n");
            return;
        }
        load_commit(commit.parent, &commit);
    }

    Index idx = commit.snapshot;
    write_index(&idx);
}

int main(int argc, char* argv[]) {
    if (argc < 2) {
        printf("Usage: minigit <command>\n");
        return 1;
    }

    if (strcmp(argv[1], "init") == 0) {
        cmd_init();
    } else if (strcmp(argv[1], "add") == 0) {
        if (argc < 3) {
            printf("Usage: minigit add <filename>\n");
            return 1;
        }
        cmd_add(argv[2]);
    } else if (strcmp(argv[1], "commit") == 0) {
        if (argc < 4 || strcmp(argv[2], "-m") != 0) {
            printf("Usage: minigit commit -m \"message\"\n");
            return 1;
        }
        cmd_commit(argv[3]);
    } else if (strcmp(argv[1], "checkout") == 0) {
        if (argc < 3) {
            printf("Usage: minigit checkout <version>\n");
            return 1;
        }
        cmd_checkout(argv[2]);
    } else if (strcmp(argv[1], "reset") == 0) {
        if (argc < 3) {
            printf("Usage: minigit reset <version>\n");
            return 1;
        }
        cmd_reset(argv[2]);
    } else {
        printf("Unknown command: %s\n", argv[1]);
        return 1;
    }

    return 0;
}
